from dataclasses import dataclass
from enum import Enum

class ExposureLevel(str, Enum):
    HIGH   = "high"    # network-accessible, handles auth, on inference path
    MEDIUM = "medium"  # internal service calls, non-auth data processing
    LOW    = "low"     # utility / offline processing

class UpgradeComplexity(str, Enum):
    LOW    = "low"    # patch or minor bump; no API changes expected
    MEDIUM = "medium" # minor bump with some deprecations
    HIGH   = "high"   # major version with breaking changes

EXPOSURE_SCORE = {
    ExposureLevel.HIGH: 3,
    ExposureLevel.MEDIUM: 2,
    ExposureLevel.LOW: 1,
}

COMPLEXITY_SCORE = {
    UpgradeComplexity.LOW: 1,
    UpgradeComplexity.MEDIUM: 2,
    UpgradeComplexity.HIGH: 3,
}

@dataclass
class DependencyRiskScore:
    record: "DependencyRecord"
    exposure: ExposureLevel
    complexity: UpgradeComplexity
    known_cve_count: int = 0
    cve_max_cvss: float = 0.0

    def risk_score(self) -> float:
        """
        Composite score 1-9. Higher = more urgent.
        CVE presence adds a multiplier to exposure.
        """
        cve_multiplier = 1.0
        if self.cve_max_cvss >= 9.0:
            cve_multiplier = 2.0
        elif self.cve_max_cvss >= 7.0:
            cve_multiplier = 1.5
        elif self.known_cve_count > 0:
            cve_multiplier = 1.25

        raw = EXPOSURE_SCORE[self.exposure] * cve_multiplier
        return round(raw, 2)

    def priority_tier(self) -> str:
        score = self.risk_score()
        if score >= 4.5:
            return "CRITICAL"
        if score >= 3.0:
            return "HIGH"
        if score >= 1.5:
            return "MEDIUM"
        return "LOW"

    def upgrade_track(self) -> str:
        if self.priority_tier() in ("CRITICAL", "HIGH"):
            if self.complexity == UpgradeComplexity.HIGH:
                return "escalate"   # mitigate now, plan upgrade project
            return "prioritise"     # patch within 7 days
        if self.complexity == UpgradeComplexity.HIGH:
            return "plan"           # allocate sprint capacity
        return "maintain"           # routine upgrade cadence

import subprocess, json
from pathlib import Path

def parse_poetry_lock(lockfile: Path) -> list[dict]:
    """
    Extract name + version from poetry.lock.
    Returns list of {name, version, category} dicts.
    """
    import re
    packages = []
    current: dict | None = None
    for line in lockfile.read_text().splitlines():
        if line.startswith("[[package]]"):
            if current:
                packages.append(current)
            current = {}
        elif current is not None:
            m = re.match(r'^(name|version|category) = "(.+)"', line)
            if m:
                current[m.group(1)] = m.group(2)
    if current:
        packages.append(current)
    return packages

def latest_pypi_version(package_name: str) -> str | None:
    """Fetch latest version from PyPI JSON API."""
    import urllib.request, json as _json
    try:
        url = f"https://pypi.org/pypi/{package_name}/json"
        with urllib.request.urlopen(url, timeout=5) as resp:
            data = _json.loads(resp.read())
        return data["info"]["version"]
    except Exception:
        return None

def build_inventory(lockfile: Path) -> list[dict]:
    packages = parse_poetry_lock(lockfile)
    inventory = []
    for pkg in packages:
        latest = latest_pypi_version(pkg["name"])
        inventory.append({
            "name": pkg["name"],
            "installed": pkg.get("version", "unknown"),
            "latest": latest or "fetch_failed",
            "kind": "direct" if pkg.get("category") == "main" else "transitive",
        })
    return inventory

from dataclasses import dataclass
from datetime import date, timedelta

@dataclass
class UpgradeTask:
    record: "DependencyRecord"
    score: "DependencyRiskScore"

    def target_completion_date(self, from_date: date) -> date:
        track = self.score.upgrade_track()
        days = {
            "escalate":   7,     # mitigate immediately, plan upgrade in 30d
            "prioritise": 7,
            "plan":       90,
            "maintain":   30,
        }
        return from_date + timedelta(days=days[track])

    def suggested_pr_title(self) -> str:
        rec = self.record
        major, minor, patch = rec.version_lag()
        bump_type = "major" if major > 0 else ("minor" if minor > 0 else "patch")
        return (
            f"deps({rec.ecosystem}): upgrade {rec.name} "
            f"{rec.installed_version} -> {rec.latest_version} "
            f"[{bump_type}] [{self.score.priority_tier()}]"
        )

def prioritised_queue(
    scored: list["DependencyRiskScore"],
) -> list[UpgradeTask]:
    """
    Returns UpgradeTasks sorted: higher risk score first,
    lower complexity first within the same score tier.
    """
    def sort_key(s: "DependencyRiskScore"):
        complexity_rank = {
            UpgradeComplexity.LOW: 0,
            UpgradeComplexity.MEDIUM: 1,
            UpgradeComplexity.HIGH: 2,
        }
        return (-s.risk_score(), complexity_rank[s.complexity])

    return [UpgradeTask(s.record, s) for s in sorted(scored, key=sort_key)]

from dataclasses import dataclass
from enum import Enum

class CVESeverity(str, Enum):
    CRITICAL  = "critical"
    HIGH      = "high"
    MEDIUM    = "medium"
    LOW       = "low"
    UNKNOWN   = "unknown"

@dataclass
class CVEFinding:
    cve_id: str
    package_name: str
    installed_version: str
    fixed_version: str | None
    severity: CVESeverity
    cvss_score: float
    description: str

@dataclass
class ScoredFinding:
    finding: CVEFinding
    risk_score: "DependencyRiskScore"

    def action(self) -> str:
        if self.finding.fixed_version is None:
            return "no_patch_available: apply_mitigation"
        return f"upgrade_to_{self.finding.fixed_version}: track={self.risk_score.upgrade_track()}"

    def sla_deadline_days(self) -> int:
        sev = self.finding.severity
        if sev == CVESeverity.CRITICAL:
            return 1
        if sev == CVESeverity.HIGH:
            return 3
        if sev == CVESeverity.MEDIUM:
            return 30
        return 90

def merge_findings_with_inventory(
    findings: list[CVEFinding],
    scored_inventory: list["DependencyRiskScore"],
) -> list[ScoredFinding]:
    """
    Joins CVE scanner output with the scored inventory.
    Unmatched findings (package not in inventory) are logged as
    inventory gaps and excluded from the queue.
    """
    score_by_name = {s.record.name: s for s in scored_inventory}
    result = []
    for f in findings:
        score = score_by_name.get(f.package_name)
        if score is None:
            print(f"INVENTORY GAP: {f.cve_id} for {f.package_name} — not in inventory")
            continue
        result.append(ScoredFinding(finding=f, risk_score=score))
    return result
